// Check for Academic Oversight DOM presence on methodology pages
// data-testid="academic-oversight" MUST be present (E-E-A-T authority)
const pages = $input.all();
const results = { valid: true, issues: [], checkedPages: [] };

for (const item of pages) {
  const body = item.json?.body ?? item.json?.data ?? '';
  const url = item.json?.url ?? 'unknown';

  const hasAcademicBlock = /data-testid=["']academic-oversight["']/.test(body);
  const hasProfNataraj = /Neela Nataraj|IIT Bombay/.test(body);

  results.checkedPages.push({
    url,
    academicBlock: hasAcademicBlock,
    profNataraj: hasProfNataraj,
    status: hasAcademicBlock ? 'PASS' : 'FAIL'
  });

  if (!hasAcademicBlock) {
    results.valid = false;
    results.issues.push(`ACADEMIC_OVERSIGHT_MISSING: ${url} — data-testid="academic-oversight" not found in DOM`);
  }

  if (!hasProfNataraj) {
    results.issues.push(`PROF_REFERENCE_MISSING: ${url} — "Prof. Dr. Neela Nataraj" or "IIT Bombay" not found`);
  }
}

console.log(`[W21] Checked ${results.checkedPages.length} pages: ${results.valid ? 'ALL PASS' : results.issues.length + ' ISSUES'}`);

return [{ json: results }];

